def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0
        for n in range(1, 10):
            base = (1 / (n**1.5)) * (ratio ** n)
            if n % 4 == 0:
                base *= 1.3 + 0.05 * (capacity % 5)
            elif n % 3 == 0:
                base *= 0.9 + 0.02 * (capacity % 7)
            else:
                base *= 1 - 0.01 * (capacity % 4)
            score += base
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.08 * capacity:
            score *= 1.7
        elif remaining < 0.15 * capacity:
            score *= 1.2
        elif remaining > 0.5 * capacity:
            score *= 0.6
        else:
            score *= 0.85
        mod_conditions = {3: False, 4: False, 5: False, 6: False}
        for mod in mod_conditions.keys():
            mod_conditions[mod] = int(capacity) % mod == 0
        if mod_conditions[3] and mod_conditions[4] and mod_conditions[5]:
            score -= 0.15 * (capacity / 9)
        elif mod_conditions[3] and mod_conditions[5]:
            score -= 0.1 * (capacity / 12)
        elif mod_conditions[4] and mod_conditions[6]:
            score -= 0.12 * (capacity / 14)
        elif mod_conditions[3]:
            score -= 0.06 * (capacity / 11)
        elif mod_conditions[5]:
            score -= 0.09 * (capacity / 18)
        else:
            score -= 0.04 * (capacity / 25)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.012 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 1.5 * threshold:
                penalty += 0.15 * k
            else:
                penalty -= 0.04 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1, 5):
                val = capacity / m
                delta = abs(val - item)
                if delta < 0.015 * val:
                    score *= (1 + 0.07 * m)
                elif delta < 0.03 * val:
                    score *= (1 + 0.03 * m)
        norm_factor = np.log1p(capacity)
        score /= norm_factor
        priorities[i] = score
    return priorities
